function solve(points) {
    const n = points.length;
    if (n < 4) return 0;
    let count = 0;
    const lines = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const x1 = points[i][0], y1 = points[i][1];
            const x2 = points[j][0], y2 = points[j][1];
            let key;
            if (x1 === x2) {
                key = `inf_${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope}_${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key).push([i, j]);
        }
    }

    const processed = new Set();
    for (const [key, pairs] of lines) {
        if (pairs.length < 2) continue;
        for (let i = 0; i < pairs.length; i++) {
            for (let j = i + 1; j < pairs.length; j++) {
                const [a, b] = pairs[i];
                const [c, d] = pairs[j];
                const set = new Set([a, b, c, d]);
                if (set.size === 4) {
                    const sorted = Array.from(set).sort((x, y) => x - y);
                    const hash = sorted.join(',');
                    if (!processed.has(hash)) {
                        processed.add(hash);
                        count++;
                    }
                }
            }
        }
    }

    return count;
}

