use std::collections::{HashMap, HashSet};

fn solve(points: Vec<Vec<i64>>) -> i64 {
    let n = points.len();
    if n < 4 {
        return 0;
    }
    let mut count = 0;
    let mut lines: HashMap<String, Vec<(usize, usize)>> = HashMap::new();

    for i in 0..n {
        for j in i + 1..n {
            let x1 = points[i][0];
            let y1 = points[i][1];
            let x2 = points[j][0];
            let y2 = points[j][1];
            let key = if x1 == x2 {
                format!("inf_{}", x1)
            } else {
                let slope = (y2 - y1) as f64 / (x2 - x1) as f64;
                let intercept = y1 as f64 - slope * x1 as f64;
                format!("{}_{}", slope, intercept)
            };
            lines.entry(key).or_default().push((i, j));
        }
    }

    let mut processed: HashSet<String> = HashSet::new();
    for (_, pairs) in lines {
        if pairs.len() < 2 {
            continue;
        }
        for i in 0..pairs.len() {
            for j in i + 1..pairs.len() {
                let (a, b) = pairs[i];
                let (c, d) = pairs[j];
                let mut set = HashSet::new();
                set.insert(a);
                set.insert(b);
                set.insert(c);
                set.insert(d);
                if set.len() == 4 {
                    let mut sorted: Vec<usize> = set.into_iter().collect();
                    sorted.sort();
                    let hash = sorted.iter().map(|x| x.to_string()).collect::<Vec<_>>().join(",");
                    if !processed.contains(&hash) {
                        processed.insert(hash);
                        count += 1;
                    }
                }
            }
        }
    }

    count
}
